import React, { useEffect, useState, useRef } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { io } from 'socket.io-client';
import { useAuth } from '../context/AuthContext';
import { apiCall } from '../services/api'; 
import ChatBox from '../components/ChatBox';
import PollComponent from '../components/PollComponent';

const SOCKET_URL = process.env.REACT_APP_SOCKET_URL || 'http://localhost:5000';

export default function GroupRoomPage() {
    const { id: groupId } = useParams();
    const { user, token } = useAuth();
    const navigate = useNavigate();

    const [group, setGroup] = useState(null);
    const [messages, setMessages] = useState([]);
    const [loading, setLoading] = useState(true);
    const socketRef = useRef(null);

    useEffect(() => {
        const init = async () => {
            try {
                const [groupRes, msgRes] = await Promise.all([
                    apiCall(`/groups/${groupId}`),
                    apiCall(`/groups/${groupId}/messages`)
                ]);

                setGroup(groupRes.data);
                setMessages(msgRes.data);
            } catch (err) {
                console.error("Failed to fetch group room data:", err);
                navigate('/groups');
                return;
            } finally {
                setLoading(false);
            }

            const socket = io(SOCKET_URL, { auth: { token } });
            socketRef.current = socket;

            socket.emit('joinGroup', { groupId });

            socket.on('newMessage', (msg) => {
                setMessages((prev) => [...prev, msg]);
            });

            socket.on('pollUpdated', (updatedPoll) => {
                setMessages((prev) =>
                    prev.map((m) =>
                        m.pollId?._id === updatedPoll._id
                            ? { ...m, pollId: updatedPoll }
                            : m
                    )
                );
            });

            socket.on('error', (err) => console.error('Socket error:', err.message));
        };

        init();

        return () => socketRef.current?.disconnect();
    }, [groupId, token]);

    if (loading) return <div className="p-8 text-center text-gray-400">Loading group...</div>;
    if (!group) return null;

    return (
        <div className="flex flex-col h-screen max-w-3xl mx-auto">
            <div className="bg-white border-b px-6 py-4 flex items-center gap-3">
                <button onClick={() => navigate('/groups')} className="text-gray-400 hover:text-gray-600 text-xl">←</button>
                <div>
                    <h1 className="font-bold text-gray-800">{group.name}</h1>
                    <p className="text-xs text-gray-400">{group.members.length} members</p>
                </div>
            </div>

            <ChatBox
                messages={messages}
                currentUser={user}
                socket={socketRef.current}
                groupId={groupId}
            />
        </div>
    );
}
